CustomField.formula:
IF(
  NOT(ISBLANK(Start_Date__c)),

  /* Calculate years and months using either End Date or TODAY() if blank */
  TEXT(
    FLOOR(
      (IF(ISBLANK(Graduation_Completion_Date__c), TODAY(), Graduation_Completion_Date__c) - Start_Date__c) / 365
    )
  ) & " yr" &
  IF(
    FLOOR(
      (IF(ISBLANK(Graduation_Completion_Date__c), TODAY(), Graduation_Completion_Date__c) - Start_Date__c) / 365
    ) > 1,
    "s",
    ""
  ) & " " &
  TEXT(
    FLOOR(
      MOD(
        (IF(ISBLANK(Graduation_Completion_Date__c), TODAY(), Graduation_Completion_Date__c) - Start_Date__c),
        365
      ) / 30
    )
  ) & " mo" &
  IF(
    FLOOR(
      MOD(
        (IF(ISBLANK(Graduation_Completion_Date__c), TODAY(), Graduation_Completion_Date__c) - Start_Date__c),
        365
      ) / 30
    ) > 1,
    "s",
    ""
  ) &
  IF(ISBLANK(Graduation_Completion_Date__c), " (Current)", ""),

  ""
)
